import React, { useState, useEffect, useCallback } from 'react';
import axios from 'axios';
import Sidebar from './Sidebar';
import CreateForm from './CreateForm';
import ManageList from './ManageList';
import InquiryList from './InquiryList';

const AdminPanel = () => {
  const [activeTab, setActiveTab] = useState('create');
  const [postType, setPostType] = useState('blog');
  const [category, setCategory] = useState('Electronics');
  const [formData, setFormData] = useState({ title: '', description: '', loc: '', salary: '', type: 'On-site' });
  const [file, setFile] = useState(null);
  const [items, setItems] = useState([]);
  const [inquiries, setInquiries] = useState([]);
  const [isEditing, setIsEditing] = useState(false);
  const [editId, setEditId] = useState(null);

  // Memoized fetch functions to fix useEffect dependency warnings
  const fetchItems = useCallback(async () => {
    try {
      const url = postType === 'job' 
        ? 'http://localhost:5001/api/jobs' 
        : `http://localhost:5001/api/blog/${category}`;
      const res = await axios.get(url);
      setItems(Array.isArray(res.data) ? res.data : []);
    } catch (err) { 
      console.error("Fetch Items Error:", err);
      setItems([]); 
    }
  }, [postType, category]);

  const fetchInquiries = useCallback(async () => {
    try {
      const res = await axios.get('http://localhost:5001/api/contact');
      // Handling both array and object responses
      const data = Array.isArray(res.data) ? res.data : (res.data.inquiries || []);
      setInquiries(data);
    } catch (err) { 
      console.error("Fetch Inquiries Error:", err);
      setInquiries([]); 
    }
  }, []);

  useEffect(() => {
    if (activeTab === 'manage') fetchItems();
    if (activeTab === 'inquiries') fetchInquiries();
  }, [activeTab, fetchItems, fetchInquiries]);

  const handleEdit = (item) => {
    setIsEditing(true);
    setEditId(item._id);
    setActiveTab('create');
    setFormData({ 
      title: item.title, 
      description: item.description || '', 
      loc: item.loc || '', 
      salary: item.salary || '', 
      type: item.type || 'On-site' 
    });
    if (item.category) setCategory(item.category);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (isEditing) {
        const endpoint = postType === 'job' ? `jobs/${editId}` : `blog/${editId}`;
        await axios.patch(`http://localhost:5001/api/admin/${endpoint}`, formData);
        alert("Updated Successfully!");
      } else {
        if (postType === 'job') {
          await axios.post('http://localhost:5001/api/admin/jobs', formData);
        } else {
          const data = new FormData();
          data.append('category', category); 
          data.append('title', formData.title);
          data.append('description', formData.description); 
          if (file) data.append('image', file);
          await axios.post('http://localhost:5001/api/admin/blog', data);
        }
        alert("Published Successfully!");
      }
      // Reset State
      setFormData({ title: '', description: '', loc: '', salary: '', type: 'On-site' });
      setFile(null);
      setIsEditing(false);
      setEditId(null);
    } catch (err) { 
      alert("Action Failed!"); 
    }
  };

  const handleDelete = async (id, type) => {
    if (window.confirm("Are you sure you want to delete this?")) {
      try {
        const endpoint = type === 'inquiry' ? 'contact' : (postType === 'job' ? 'jobs' : 'blog');
        await axios.delete(`http://localhost:5001/api/admin/${endpoint}/${id}`);
        type === 'inquiry' ? fetchInquiries() : fetchItems();
        alert("Deleted successfully");
      } catch (err) {
        alert("Delete failed");
      }
    }
  };

  return (
    <div className="flex min-h-screen bg-gray-50 pt-20 font-sans">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        setIsEditing={setIsEditing} 
        postType={postType} 
        setPostType={setPostType} 
        category={category} 
        setCategory={setCategory} 
      />

      <div className="flex-1 ml-80 p-12">
        {activeTab === 'create' && (
          <CreateForm 
            isEditing={isEditing} 
            handleSubmit={handleSubmit} 
            postType={postType} 
            formData={formData} 
            setFormData={setFormData} 
            setFile={setFile} 
          />
        )}

        {activeTab === 'manage' && (
          <ManageList 
            items={items} 
            handleEdit={handleEdit} 
            handleDelete={handleDelete} 
          />
        )}

        {activeTab === 'inquiries' && (
          <InquiryList 
            inquiries={inquiries} 
            handleDelete={handleDelete} 
          />
        )}
      </div>
    </div>
  );
};

export default AdminPanel;
